class Solution {
    public int[] findOrder(int numCourses, int[][] prerequisites) {
        int[] res = new int[numCourses];
        int[] visited = new int[numCourses];
        List<Integer>[] graph = new List[numCourses];
        for (int i = 0; i < numCourses; i++) {
            graph[i] = new ArrayList<>();
        }
        for (int[] p : prerequisites) {
            graph[p[1]].add(p[0]);
        }
        int index = 0;
        for (int i = 0; i < numCourses; i++) {
            if (visited[i] == 0) {
                if (!dfs(graph, visited, res, i, index)) {
                    return new int[0];
                }
            }
        }
        return res;
    }
    private boolean dfs(List<Integer>[] graph, int[] visited, int[] res, int i, int index) {
        if (visited[i] == 1) {
            return false;
        }
        if (visited[i] == 2) {
            return true;
        }
        visited[i] = 1;
        for (int j : graph[i]) {
            if (!dfs(graph, visited, res, j, index)) {
                return false;
            }
        }
        visited[i] = 2;
        res[index++] = i;
        return true;
    }
}
